  ('social-worker-moex-07564', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會學家主張文化是學習而來，此論點是在下列何種脈絡裡發展出來的？', '["宗教信仰", "家庭生活", "地理環境", "社會互動"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "ed6ad7e1f554", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
